// ═══════════════════════════════════════════════════════
// ⚙️  CONFIGURATION — Remplir ces valeurs avant utilisation
// ═══════════════════════════════════════════════════════
const CONFIG = {
  ANTHROPIC_API_KEY: 'sk-ant-api03-REMPLACER',
  BREVO_API_KEY:     'xkeysib-REMPLACER',
  LEADFLOW_URL:      'https://REMPLACER.railway.app',   // sans slash final
  AGENCE_NAME:       'Nom de l\'agence',
  AGENT_NAME:        'Prénom Nom',
  AGENT_EMAIL:       'agent@agence.com',
  AGENT_PHONE:       '+33XXXXXXXXX',                    // format E.164
  SENDER_EMAIL:      'noreply@agence.com',              // email expéditeur Brevo
};
// ═══════════════════════════════════════════════════════

const raw  = $input.first().json;
const body = raw.body ? (typeof raw.body === 'string' ? JSON.parse(raw.body) : raw.body) : raw;

const contact  = body.data?.contact  || body.contact  || body;
const property = body.data?.property || body.property || {};

const lead = {
  id:      'sw_' + (contact.property_id || property.id || Date.now()),
  prenom:  contact.first_name || '',
  nom:     contact.last_name  || '',
  email:   contact.email      || '',
  tel:     contact.phone      || '',
  message: contact.message    || '',
  source:  contact.source     || body.event || 'webhook',
  bien:    property.description || '',
  ville:   property.location?.city || '',
  projet:  property.description ? 'Intéressé par : ' + property.description : '',
};

return [{ json: { ...lead, ...CONFIG } }];

const data = $input.first().json;

// Lignes de signature : on n'inclut que les valeurs renseignées
const sigLines = [
  data.AGENT_NAME  ? `Nom : ${data.AGENT_NAME}`   : null,
  data.AGENCE_NAME ? `Agence : ${data.AGENCE_NAME}` : null,
  data.AGENT_EMAIL ? `Email : ${data.AGENT_EMAIL}`  : null,
  data.AGENT_PHONE ? `Téléphone : ${data.AGENT_PHONE}` : null,
].filter(Boolean);
const agentInfo = sigLines.join('\n');

// Bloc signature finale (sans libellés, juste les valeurs)
const sigValues = [
  data.AGENT_NAME,
  data.AGENCE_NAME,
  data.AGENT_EMAIL,
  data.AGENT_PHONE,
].filter(v => v && v.trim() !== '').join('\n');

const systemPrompt = `Tu es un conseiller immobilier. Voici qui tu es :

${agentInfo}

Ta mission : analyser le lead entrant et générer des communications personnalisées au nom de cet agent.

Règle absolue sur la signature : termine chaque email exactement par :
${sigValues}
Ne mets jamais de placeholder comme [NOM], [EMAIL] ou [TÉLÉPHONE]. Si une info n'est pas fournie ci-dessus, tu ne l'inventes pas et tu ne laisses pas d'espace vide pour elle.

## Critères de température
- CHAUD (score 80-100) : projet précis, délai < 3 mois, fort engagement
- TIÈDE (score 50-79) : projet en cours, délai 3-6 mois, engagement modéré
- FROID (score 0-49) : projet vague, délai > 6 mois ou peu d'informations

## Emails à rédiger (français, ton professionnel et chaleureux)
- J0 Bienvenue : accuser réception, valeur ajoutée agence, inviter à échanger
- J2 Relance : apporter de la valeur (conseil marché, info locale), proposition concrète d'appel
- J7 Dernier contact : ton chaleureux, laisser la porte grande ouverte

Réponds UNIQUEMENT avec un JSON valide sans bloc markdown :
{
  "score": <entier 0-100>,
  "temperature": "<chaud|tiede|froid>",
  "score_raison": "<1 phrase expliquant le score>",
  "email_bienvenue": "<corps complet email J0 sans ligne d'objet>",
  "relance_j2": "<corps complet email J2 sans ligne d'objet>",
  "relance_j7": "<corps complet email J7 sans ligne d'objet>",
  "email_subjects": {
    "j0": "<objet email J0>",
    "j2": "<objet email J2>",
    "j7": "<objet email J7>"
  }
}`;

const userPrompt = `Analyse ce lead et génère les communications :

Source : ${data.source || 'formulaire web'}
Prénom : ${data.prenom || '(non renseigné)'}
Nom : ${data.nom || '(non renseigné)'}
Email : ${data.email || ''}
Téléphone : ${data.tel || '(non renseigné)'}
Bien recherché : ${data.bien || '(non précisé)'}
Ville : ${data.ville || '(non précisée)'}
Projet : ${data.projet || '(non précisé)'}
Message : ${data.message || '(aucun message)'}`;

return [{ json: { ...data, _systemPrompt: systemPrompt, _userPrompt: userPrompt } }];

const claudeResponse = $input.first().json;
const cfg  = $('⚙️ Configuration').first().json;
const lead = $('Construire Prompt Claude').first().json;

const rawText = claudeResponse.content?.[0]?.text || '';
let parsed;
try {
  const cleaned = rawText.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Parse Claude impossible. Réponse : ' + rawText.substring(0, 300));
}

if (!parsed.score || !parsed.temperature || !parsed.email_bienvenue) {
  throw new Error('Réponse Claude incomplète : ' + JSON.stringify(parsed).substring(0, 200));
}

// ── Palette couleurs dashboard ──────────────────────────
const C = {
  ink:    '#1c1a16',
  cream:  '#f7f4ee',
  cream2: '#f0ebe0',
  white:  '#ffffff',
  gold:   '#b8893a',
  gold2:  '#d4a853',
  muted:  '#8a8478',
  border: '#e0d8c8',
};

function buildEmail(bodyText, agentName, agentEmail) {
  if (!bodyText) return '';
  const esc = bodyText
    .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  const paragraphs = esc
    .split(/\n\n+/)
    .map(p => `<p style="margin:0 0 16px 0;color:${C.ink};line-height:1.7">${p.replace(/\n/g,'<br>')}</p>`)
    .join('');
  return `<!DOCTYPE html>
<html lang="fr"><head><meta charset="UTF-8">
<link href="https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,400;0,600;1,400&family=Figtree:wght@300;400;500;600&display=swap" rel="stylesheet">
</head>
<body style="margin:0;padding:0;background:${C.cream};font-family:'Figtree',Helvetica,Arial,sans-serif">
<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:${C.cream}">
<tr><td align="center" style="padding:32px 16px">
<table role="presentation" width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%">

<!-- HEADER -->
<tr><td style="background:${C.ink};border-radius:12px 12px 0 0;padding:20px 32px">
  <table role="presentation" cellpadding="0" cellspacing="0"><tr>
    <td style="background:linear-gradient(135deg,${C.gold},${C.gold2});border-radius:8px;width:32px;height:32px;text-align:center;vertical-align:middle;color:${C.white};font-size:14px">✦</td>
    <td style="padding-left:10px;font-family:'Cormorant Garamond',Georgia,serif;font-size:22px;font-weight:400;color:${C.cream}">
      Lead<em style="font-style:italic;color:${C.gold2}">Flow</em>
    </td>
  </tr></table>
</td></tr>

<!-- BODY -->
<tr><td style="background:${C.white};padding:36px 40px;border-left:1px solid ${C.border};border-right:1px solid ${C.border}">
  ${paragraphs}
</td></tr>

<!-- CTA -->
<tr><td style="background:${C.white};padding:0 40px 32px;border-left:1px solid ${C.border};border-right:1px solid ${C.border};text-align:center">
  <a href="mailto:${agentEmail}" style="display:inline-block;background:${C.gold};color:${C.white};text-decoration:none;padding:12px 28px;border-radius:8px;font-family:'Figtree',Helvetica,Arial,sans-serif;font-weight:600;font-size:14px">Répondre à votre conseiller</a>
</td></tr>

<!-- FOOTER -->
<tr><td style="background:${C.cream2};border:1px solid ${C.border};border-radius:0 0 12px 12px;padding:20px 32px;text-align:center">
  <p style="margin:0;color:${C.muted};font-size:11px;letter-spacing:.5px">${agentName} &nbsp;·&nbsp; Propulsé par <span style="color:${C.gold};font-weight:500">LeadFlow</span></p>
</td></tr>

</table></td></tr></table>
</body></html>`;
}

// ── Infos agent depuis le nœud Configuration ────────────
const agentName   = cfg.AGENT_NAME   || 'Votre agence';
const agentEmail  = cfg.AGENT_EMAIL  || 'contact@agence.com';
const senderEmail = cfg.SENDER_EMAIL || agentEmail;
const agentPhone  = cfg.AGENT_PHONE  || '';

const fullName = [lead.prenom, lead.nom].filter(Boolean).join(' ') || lead.email;
const temp     = (parsed.temperature || 'froid').toLowerCase();
const tempIcon = temp === 'chaud' ? '🔥' : temp === 'tiede' ? '🌤️' : '❄️';
const tempLabel = `${tempIcon} ${temp.toUpperCase()}`;

const subjects  = parsed.email_subjects || {};
const j0Subject = subjects.j0 || 'Votre demande immobilière';
const j2Subject = subjects.j2 || 'Un suivi sur votre projet';
const j7Subject = subjects.j7 || 'Toujours disponible pour vous';

// Validation email — stoppe tôt avec un message clair
if (!lead.email || !String(lead.email).includes('@')) {
  throw new Error(
    '[LeadFlow] Email invalide ou manquant. ' +
    'Champs reçus dans lead : ' + Object.keys(lead).filter(k => !k.startsWith('_') && !k.startsWith('ANTHROPIC') && !k.startsWith('BREVO') && !k.startsWith('LEADFLOW') && !k.startsWith('AGENT') && !k.startsWith('SENDER')).join(', ') + '. ' +
    'Email reçu : "' + (lead.email || '(vide)') + '". ' +
    'Vérifiez que le webhook envoie bien un champ "email" dans le body.'
  );
}

const sender        = { name: agentName, email: senderEmail };
const leadRecipient = [{ email: lead.email, name: fullName || lead.email }];

// ── Payloads Brevo pré-construits (réutilisables après Wait) ─
const brevoJ0 = JSON.stringify({
  sender, to: leadRecipient,
  subject: j0Subject,
  htmlContent: buildEmail(parsed.email_bienvenue, agentName, agentEmail)
});

const brevoJ2 = JSON.stringify({
  sender, to: leadRecipient,
  subject: j2Subject,
  htmlContent: buildEmail(parsed.relance_j2, agentName, agentEmail)
});

const brevoJ7 = JSON.stringify({
  sender, to: leadRecipient,
  subject: j7Subject,
  htmlContent: buildEmail(parsed.relance_j7, agentName, agentEmail)
});

// ── SMS agent ────────────────────────────────────────────
const msgShort = (lead.message || '').substring(0, 120).replace(/\n/g, ' ');
const smsContent =
  `[LeadFlow] ${tempLabel}\n` +
  `${fullName}\n` +
  `${lead.email || ''}${lead.tel ? ' · ' + lead.tel : ''}\n` +
  `${lead.bien ? lead.bien + (lead.ville ? ', ' + lead.ville : '') + '\n' : ''}` +
  `Score : ${parsed.score}/100 — ${parsed.score_raison}\n` +
  (msgShort ? `"${msgShort}"` : '');

const brevoSMS = JSON.stringify({
  sender: 'LeadFlow',
  recipient: agentPhone,
  content: smsContent.substring(0, 612)
});

// ── Payload LeadFlow ─────────────────────────────────────
const leadflowPayload = JSON.stringify({
  id:              lead.id || String(Date.now()),
  prenom:          lead.prenom  || '',
  nom:             lead.nom     || '',
  email:           lead.email   || '',
  tel:             lead.tel     || '',
  bien:            lead.bien    || '',
  ville:           lead.ville   || '',
  source:          lead.source  || '',
  projet:          lead.projet  || '',
  message:         lead.message || '',
  score:           parsed.score,
  score_raison:    parsed.score_raison,
  email_bienvenue: parsed.email_bienvenue,
  relance_j2:      parsed.relance_j2,
  relance_j7:      parsed.relance_j7
});

return [{
  json: {
    id:          lead.id || String(Date.now()),
    email:       lead.email,
    prenom:      lead.prenom,
    nom:         lead.nom,
    score:       parsed.score,
    temperature: temp,
    _leadflow:   leadflowPayload,
    _brevo_j0:   brevoJ0,
    _brevo_j2:   brevoJ2,
    _brevo_j7:   brevoJ7,
    _brevo_sms:  brevoSMS
  }
}];
